// Initialize Sentry
const Sentry = require('@sentry/node');

// Get data from previous nodes
const webhook = $('Webhook').first().json;
const response = $('Fetch Response').first().json;
const survey = $('Fetch Survey').first().json;

// Extract data
const responseId = webhook.body.responseId;
const { tenant_id, answers } = response;
const { title: surveyTitle, questions } = survey;

// Breadcrumb: Processing started

Sentry.addBreadcrumb({
  message: 'Transform Q&A: Processing started',
  level: 'info',
  data: {
    responseId,
    tenant_id,
    surveyTitle,
    totalQuestions: questions.length,
    providedAnswers: Object.keys(answers).length
  }
});

// Build Q&A pairs for AI context
const qaContext = questions
  .sort((a, b) => a.order - b.order)
  .map(q => {
    const answer = answers[q.id];

    // Format answer based on type
    let formattedAnswer;
    if (Array.isArray(answer)) {
      formattedAnswer = answer.join(', ');
    } else if (answer === undefined || answer === null) {
      formattedAnswer = '(brak odpowiedzi)';
    } else {
      formattedAnswer = String(answer);
    }

    return {
      question: q.question,
      type: q.type,
      answer: formattedAnswer,
      required: q.required
    };
  });

// Build AI prompt
const prompt = `
Przeanalizuj poniższe zgłoszenie klienta i oceń jego kwalifikację do konsultacji prawnej.

TYTUŁ FORMULARZA: ${surveyTitle}

ODPOWIEDZI KLIENTA:
${qaContext.map((qa, i) => `${i + 1}. ${qa.question}\n   Odpowiedź: ${qa.answer}`).join('\n\n')}

ZADANIE:
Oceń to zgłoszenie pod kątem:
1. **Pilność sprawy** - czy wymaga natychmiastowej reakcji (0-10)
2. **Złożoność** - jak skomplikowana jest sprawa (0-10)
3. **Wartość sprawy** - potencjalna wartość ekonomiczna dla kancelarii (0-10)
4. **Prawdopodobieństwo sukcesu** - czy sprawa ma solidne podstawy (0-10)
5. **Krótkie podsumowanie** - 1-2 zdania o sprawie
6. **Rekomendacja** - czy warto umówić konsultację (QUALIFIED / DISQUALIFIED / NEEDS_MORE_INFO)
7. **Uwagi dla prawnika** - maksymalnie 3 kluczowe punkty do omówienia na spotkaniu

Odpowiedź TYLKO w formacie JSON:
{
  "urgency_score": 0-10,
  "complexity_score": 0-10,
  "value_score": 0-10,
  "success_probability": 0-10,
  "summary": "krótkie podsumowanie",
  "recommendation": "QUALIFIED | DISQUALIFIED | NEEDS_MORE_INFO",
  "notes_for_lawyer": ["punkt 1", "punkt 2", "punkt 3"]
}
`.trim();

const metadata = {
  totalQuestions: questions.length,
  answeredQuestions: qaContext.filter(qa => qa.answer !== '(brak odpowiedzi)').length
};

// Breadcrumb: Processing completed
Sentry.addBreadcrumb({
  message: 'Transform Q&A: Processing completed',
  level: 'info',
  data: {
    responseId,
    answeredQuestions: metadata.answeredQuestions,
    totalQuestions: metadata.totalQuestions,
    promptLength: prompt.length,
    hasAllRequiredAnswers: qaContext
      .filter(qa => qa.required)
      .every(qa => qa.answer !== '(brak odpowiedzi)')
  }
});

// Return structured data for AI node
return {
  responseId,
  tenant_id,
  surveyTitle,
  prompt,
  metadata
};

// Initialize Sentry
const Sentry = require('@sentry/node');

// Get AI response (from AI Agent node)
const aiResponse = $input.first().json;
const previousData = $('Transform Q&A Data').first().json;

// Breadcrumb: AI response received
Sentry.addBreadcrumb({
  message: 'Parse Output: AI response received',
  level: 'info',
  data: {
    responseId: previousData.responseId,
    hasContent: !!aiResponse.content?.[0]?.text,
    responseLength: aiResponse.content?.[0]?.text?.length || 0
  }
});

try {
  // Parse AI response (Anthropic returns content in content[0].text)
  let aiText = aiResponse.content[0].text;

  // ✅ Remove markdown code blocks if present
  if (aiText.includes('```')) {
    // Extract JSON from ```json ... ``` wrapper
    const jsonMatch = aiText.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
    if (jsonMatch && jsonMatch[1]) {
      aiText = jsonMatch[1];
    } else {
      // Fallback: simple strip
      aiText = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '');
    }
  }

  // ✅ Trim whitespace
  aiText = aiText.trim();

  const aiAnalysis = JSON.parse(aiText);

  // Structure for database (ai_qualification JSONB field)
  const qualification = {
    // Scores (0-10)
    urgency_score: aiAnalysis.urgency_score,
    complexity_score: aiAnalysis.complexity_score,
    value_score: aiAnalysis.value_score,
    success_probability: aiAnalysis.success_probability,

    // Overall score (weighted average)
    overall_score: parseFloat((
      aiAnalysis.urgency_score * 0.3 +
      aiAnalysis.value_score * 0.3 +
      aiAnalysis.success_probability * 0.25 +
      aiAnalysis.complexity_score * 0.15
    ).toFixed(1)),

    // Analysis
    summary: aiAnalysis.summary,
    recommendation: aiAnalysis.recommendation,
    notes_for_lawyer: aiAnalysis.notes_for_lawyer || [],

    // Metadata
    analyzed_at: new Date().toISOString(),
    model: 'claude-haiku-4-5',
    version: '1.0'
  };

  // Determine status change based on recommendation
  let newStatus = null;
  if (aiAnalysis.recommendation === 'QUALIFIED') {
    newStatus = 'qualified';
  } else if (aiAnalysis.recommendation === 'DISQUALIFIED') {
    newStatus = 'disqualified';
  }
  // NEEDS_MORE_INFO leaves status as 'new'

  // Breadcrumb: Parsing succeeded
  Sentry.addBreadcrumb({
    message: 'Parse Output: Parsing succeeded',
    level: 'info',
    data: {
      responseId: previousData.responseId,
      recommendation: aiAnalysis.recommendation,
      overall_score: qualification.overall_score,
      newStatus: newStatus || 'new',
      hasNotes: qualification.notes_for_lawyer.length > 0
    }
  });

  return {
    responseId: previousData.responseId,
    tenant_id: previousData.tenant_id,
    qualification,
    newStatus: newStatus || 'new'
  };

} catch (error) {
  // Breadcrumb: Parsing failed
  Sentry.addBreadcrumb({
    message: 'Parse Output: Parsing FAILED',
    level: 'error',
    data: {
      responseId: previousData.responseId,
      errorMessage: error.message,
      errorType: error.name,
      rawResponsePreview: aiResponse.content?.[0]?.text?.substring(0, 200) || 'N/A'
    }
  });

  // If parsing fails, return error structure
  return {
    responseId: previousData.responseId,
    tenant_id: previousData.tenant_id,
    qualification: {
      error: 'Failed to parse AI response',
      raw_response: aiResponse.content?.[0]?.text || JSON.stringify(aiResponse),
      analyzed_at: new Date().toISOString()
    },
    newStatus: 'new'
  };
}
